19‚Üí  --color-border-subtle: rgba(255, 255, 255, 0.05);
20‚Üí  --color-accent: #10B981;
21‚Üí  --color-accent-hover: #0EA472;
22‚Üí  --color-accent-subtle: rgba(16, 185, 129, 0.12);
