 1‚Üí@import './reset.css';
 2‚Üí@import './variables.css';
 3‚Üí
 4‚Üíhtml, body, #root {
 5‚Üí  height: 100%;
 6‚Üí  width: 100%;
 7‚Üí  overflow: hidden;
 8‚Üí}
 9‚Üí
10‚Üíbody {
11‚Üí  font-family: var(--font-ui);
12‚Üí  font-size: 13px;
13‚Üí  color: var(--color-text-primary);
14‚Üí  background: var(--color-panel-bg);
15‚Üí  -webkit-font-smoothing: antialiased;
16‚Üí  text-rendering: optimizeLegibility;
17‚Üí}
18‚Üí
19‚Üí/* Custom scrollbars ‚Äî dark theme */
20‚Üí::-webkit-scrollbar {
21‚Üí  width: 6px;
22‚Üí  height: 6px;
23‚Üí}
24‚Üí
25‚Üí::-webkit-scrollbar-track {
26‚Üí  background: transparent;
27‚Üí}
28‚Üí
29‚Üí::-webkit-scrollbar-thumb {
30‚Üí  background: rgba(255, 255, 255, 0.15);
31‚Üí  border-radius: 3px;
32‚Üí}
33‚Üí
34‚Üí::-webkit-scrollbar-thumb:hover {
35‚Üí  background: rgba(255, 255, 255, 0.25);
36‚Üí}
37‚Üí
38‚Üí/* Selection highlight */
39‚Üí::selection {
40‚Üí  background: rgba(16, 185, 129, 0.20);
41‚Üí}
42‚Üí
43‚Üí/* Focus ring */
44‚Üí:focus-visible {
45‚Üí  outline: 2px solid var(--color-accent);
46‚Üí  outline-offset: 1px;
47‚Üí}
48‚Üí
49‚Üí/* Global input focus */
50‚Üíinput:not([readonly]):focus,
51‚Üíselect:focus {
52‚Üí  border-color: var(--color-accent) !important;
53‚Üí  box-shadow: 0 0 0 2px rgba(16, 185, 129, 0.18);
54‚Üí  outline: none;
55‚Üí}
56‚Üí
57‚Üí/* Modal animations */
58‚Üí@keyframes modalOverlayIn {
59‚Üí  from { opacity: 0; }
60‚Üí  to { opacity: 1; }
61‚Üí}
62‚Üí
63‚Üí@keyframes modalDialogIn {
64‚Üí  from {
65‚Üí    opacity: 0;
66‚Üí    transform: scale(0.96) translateY(8px);
67‚Üí  }
68‚Üí  to {
69‚Üí    opacity: 1;
70‚Üí    transform: scale(1) translateY(0);
71‚Üí  }
72‚Üí}
73‚Üí
74‚Üí@keyframes fadeInUp {
75‚Üí  from {
76‚Üí    opacity: 0;
77‚Üí    transform: translateY(4px);
78‚Üí  }
79‚Üí  to {
80‚Üí    opacity: 1;
81‚Üí    transform: translateY(0);
82‚Üí  }
83‚Üí}
84‚Üí
85‚Üí@keyframes pulse {
86‚Üí  0%, 100% { opacity: 1; }
87‚Üí  50% { opacity: 0.5; }
88‚Üí}
