 36‚Üí  { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T', Icon: StairIcon },
 37‚Üí  { tool: TOOLS.SECTION, label: 'Section Cut', shortcut: 'Q', Icon: SectionCutIcon },
 38‚Üí  { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S', Icon: SlabIcon },
 39‚Üí  { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R', Icon: RoomIcon },
 40‚Üí  { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', Icon: DoorIcon },
 41‚Üí  { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N', Icon: WindowIcon },
 42‚Üí  { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C', Icon: ColumnIcon },
 43‚Üí  { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L', Icon: LandingIcon },
 44‚Üí];
 45‚Üí
 46‚Üíexport default function Toolbar({
 47‚Üí  onNew,
 48‚Üí  onSave,
 49‚Üí  onLoad,
 50‚Üí  isSidebarCollapsed,
 51‚Üí  isPropertiesCollapsed,
 52‚Üí  onToggleSidebar,
 53‚Üí  onToggleProperties,
 54‚Üí}) {
 55‚Üí  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, toolState, dispatch: editorDispatch } = useEditor();
 56‚Üí  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 57‚Üí  const {
 58‚Üí    canCopySelection,
 59‚Üí    canPaste,
 60‚Üí    copySelection,
 61‚Üí    cutSelection,
 62‚Üí    beginPaste,
 63‚Üí  } = usePlanClipboardController();
 64‚Üí  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 65‚Üí
 66‚Üí  const fixtureItems = [
 67‚Üí    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 68‚Üí    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 69‚Üí    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 70‚Üí    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 71‚Üí    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 72‚Üí    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 73‚Üí    { fixtureType: FIXTURE_TYPES.BED, label: 'Bed', Icon: BedIcon },
 74‚Üí  ];
 75‚Üí
 76‚Üí  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 77‚Üí
 78‚Üí  const handleUndo = useCallback(() => {
 79‚Üí    if (!canUndo) return;
 80‚Üí    dispatch({ type: 'UNDO' });
 81‚Üí    editorDispatch({ type: 'DESELECT' });
 82‚Üí    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 83‚Üí  }, [canUndo, dispatch, editorDispatch]);
 84‚Üí
 85‚Üí  const handleRedo = useCallback(() => {
 86‚Üí    if (!canRedo) return;
 87‚Üí    dispatch({ type: 'REDO' });
 88‚Üí    editorDispatch({ type: 'DESELECT' });
 89‚Üí    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 90‚Üí  }, [canRedo, dispatch, editorDispatch]);
 91‚Üí
 92‚Üí  const handleDetectRooms = () => {
 93‚Üí    const floor = project.floors.find(f => f.id === activeFloorId);
 94‚Üí    if (!floor || floor.walls.length < 3) {
 95‚Üí      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
 96‚Üí      return;
 97‚Üí    }
 98‚Üí    const detected = detectRooms(floor.walls, floor.columns || []);
 99‚Üí    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
100‚Üí    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
101‚Üí    editorDispatch({ type: 'DESELECT' });
102‚Üí    editorDispatch({
103‚Üí      type: 'SET_STATUS_MESSAGE',
104‚Üí      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
105‚Üí    });
106‚Üí  };
107‚Üí
108‚Üí  useEffect(() => {
109‚Üí    const handleKeyDown = (e) => {
110‚Üí      if (!(e.ctrlKey || e.metaKey)) return;
111‚Üí      if (isTypingTarget(e.target)) return;
112‚Üí
113‚Üí      const key = e.key.toLowerCase();
114‚Üí      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
115‚Üí      const isUndo = key === 'z' && !e.shiftKey;
116‚Üí      if (!isUndo && !isRedo) return;
117‚Üí
118‚Üí      e.preventDefault();
119‚Üí      if (isRedo) {
120‚Üí        handleRedo();
121‚Üí        return;
122‚Üí      }
123‚Üí      handleUndo();
124‚Üí    };
125‚Üí
126‚Üí    window.addEventListener('keydown', handleKeyDown);
127‚Üí    return () => window.removeEventListener('keydown', handleKeyDown);
128‚Üí  }, [handleRedo, handleUndo]);
129‚Üí
130‚Üí  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
131‚Üí    viewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
132‚Üí
133‚Üí  return (
134‚Üí    <div className={styles.toolbar}>
135‚Üí      {/* File & clipboard actions */}
136‚Üí      <div className={styles.group}>
137‚Üí        <button className={styles.btn} onClick={onNew} title="New Project">
138‚Üí          <NewIcon className={styles.icon} />
139‚Üí        </button>
140‚Üí        <button
141‚Üí          className={styles.btn}
142‚Üí          onClick={handleUndo}
143‚Üí          disabled={!canUndo}
144‚Üí          title="Undo (Ctrl+Z)"
145‚Üí          aria-label="Undo"
146‚Üí        >
147‚Üí          <UndoIcon className={styles.icon} />
148‚Üí        </button>
149‚Üí        <button
150‚Üí          className={styles.btn}
151‚Üí          onClick={handleRedo}
152‚Üí          disabled={!canRedo}
153‚Üí          title="Redo (Ctrl+Shift+Z)"
154‚Üí          aria-label="Redo"
155‚Üí        >
156‚Üí          <RedoIcon className={styles.icon} />
157‚Üí        </button>
158‚Üí        <button
159‚Üí          className={styles.saveBtn}
160‚Üí          onClick={onSave}
161‚Üí          title="Save (Ctrl+S)"
162‚Üí          data-dirty={isDirty}
163‚Üí        >
164‚Üí          <SaveIcon className={styles.icon} />
165‚Üí        </button>
166‚Üí        <div className={styles.divider} />
167‚Üí        <button className={styles.btn} onClick={onLoad} title="Load Project">
168‚Üí          <LoadIcon className={styles.icon} />
169‚Üí        </button>
170‚Üí        <button
171‚Üí          className={styles.btn}
172‚Üí          onClick={copySelection}
173‚Üí          disabled={!canCopySelection}
174‚Üí          title="Copy (Ctrl+C)"
175‚Üí        >
176‚Üí          <CopyIcon className={styles.icon} />
177‚Üí        </button>
178‚Üí        <button
179‚Üí          className={styles.btn}
180‚Üí          onClick={cutSelection}
181‚Üí          disabled={!canCopySelection}
182‚Üí          title="Cut (Ctrl+X)"
183‚Üí        >
184‚Üí          <CutIcon className={styles.icon} />
185‚Üí        </button>
186‚Üí        <button
187‚Üí          className={styles.btn}
188‚Üí          onClick={() => beginPaste()}
189‚Üí          disabled={!canPaste}
190‚Üí          title="Paste (Ctrl+V)"
191‚Üí        >
192‚Üí          <PasteIcon className={styles.icon} />
193‚Üí        </button>
194‚Üí      </div>
195‚Üí
196‚Üí      {/* View mode segmented control */}
197‚Üí      <div className={styles.segmentedGroup}>
198‚Üí        {viewModes.map(({ key, label, viewMode: vm }) => (
199‚Üí          <button
200‚Üí            key={key}
201‚Üí            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
202‚Üí            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
203‚Üí            title={`${label} View`}
204‚Üí          >
205‚Üí            {label}
206‚Üí          </button>
207‚Üí        ))}
208‚Üí        <button
209‚Üí          className={activeViewKey === 'sheets' ? styles.segmentedBtnActive : styles.segmentedBtn}
210‚Üí          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
211‚Üí          title="Sheet Workspace"
212‚Üí        >
213‚Üí          Sheets
214‚Üí        </button>
215‚Üí      </div>
216‚Üí
217‚Üí      {/* Tool palette - inline row of 12 icons */}
218‚Üí      <div className={styles.toolPalette}>
219‚Üí        <span className={styles.groupLabel}>Tools</span>
220‚Üí        {toolItems.map(({ tool, label, shortcut, Icon }) => (
221‚Üí          <button
222‚Üí            key={tool}
223‚Üí            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
224‚Üí            onClick={() => setTool(tool)}
225‚Üí            disabled={!isPlanView}
226‚Üí            title={`${label} (${shortcut})`}
227‚Üí            aria-label={label}
228‚Üí          >
229‚Üí            <Icon className={styles.toolPaletteIcon} />
230‚Üí          </button>
231‚Üí        ))}
232‚Üí      </div>
233‚Üí
234‚Üí      {/* Fixtures palette */}
235‚Üí      <div className={styles.fixturePalette}>
236‚Üí        <span className={styles.fixturePaletteLabel}>Fixtures</span>
237‚Üí        {fixtureItems.map(({ fixtureType, label, Icon }) => {
238‚Üí          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
239‚Üí          return (
240‚Üí            <button
241‚Üí              key={fixtureType}
242‚Üí              className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
243‚Üí              onClick={() => {
244‚Üí                editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
245‚Üí                editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
246‚Üí              }}
247‚Üí              disabled={!isPlanView}
248‚Üí              title={`${label} (F)`}
249‚Üí              aria-label={label}
250‚Üí            >
251‚Üí              <Icon className={styles.toolPaletteIcon} />
252‚Üí            </button>
253‚Üí          );
254‚Üí        })}
255‚Üí      </div>
256‚Üí
257‚Üí      {/* Panel toggles & utility toggles */}
258‚Üí      <div className={styles.group}>
259‚Üí        <span className={styles.groupLabel}>Panels</span>
260‚Üí        <button
261‚Üí          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
262‚Üí          onClick={onToggleSidebar}
263‚Üí          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
264‚Üí          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
265‚Üí        >
266‚Üí          <SidebarIcon className={styles.icon} />
267‚Üí        </button>
268‚Üí        <button
269‚Üí          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
270‚Üí          onClick={onToggleProperties}
271‚Üí          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
272‚Üí          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
273‚Üí        >
274‚Üí          <PropertiesIcon className={styles.icon} />
275‚Üí        </button>
276‚Üí        <div className={styles.divider} />
277‚Üí        <span className={styles.groupLabel}>Display</span>
278‚Üí        <button
279‚Üí          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
280‚Üí          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
281‚Üí          title="Toggle Grid"
282‚Üí          aria-label="Toggle Grid"
283‚Üí        >
284‚Üí          <GridIcon className={styles.icon} />
285‚Üí        </button>
286‚Üí        <button
287‚Üí          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
288‚Üí          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
289‚Üí          title="Toggle Snap"
290‚Üí          aria-label="Toggle Snap"
291‚Üí        >
292‚Üí          <SnapIcon className={styles.icon} />
293‚Üí        </button>
294‚Üí        <button
295‚Üí          className={styles.btn}
296‚Üí          onClick={handleDetectRooms}
