.canvasContainer {
  width: 100%;
  height: 100%;
  overflow: hidden;
  position: relative;
  background: var(--color-background);
}

.svg {
  width: 100%;
  height: 100%;
  display: block;
}

.statusBar {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 26px;
  background: var(--color-panel-bg);
  border-top: 1px solid var(--color-border);
  box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.03);
  display: flex;
  align-items: center;
  gap: var(--space-xl);
  padding: 0 var(--space-lg);
  font-size: 11px;
  letter-spacing: 0.02em;
  color: var(--color-text-secondary);
  font-family: var(--font-blueprint);
  user-select: none;
}

.expandBtn {
  position: absolute;
  bottom: 32px;
  right: 8px;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  background: var(--color-surface-elevated);
  border: 1px solid var(--color-border);
  color: var(--color-text-secondary);
  cursor: pointer;
  opacity: 0.7;
  transition: opacity var(--duration-fast), background var(--duration-fast);
  z-index: 5;
}

.expandBtn:hover {
  opacity: 1;
  background: white;
}

.expandBtn svg {
  width: 14px;
  height: 14px;
}

.statusMessage {
  margin-left: auto;
  color: var(--color-accent);
  font-family: var(--font-ui);
  font-weight: 500;
  animation: fadeInUp 0.2s var(--ease-out);
}

.layout {
  display: grid;
  grid-template-rows: var(--toolbar-height) 1fr;
  grid-template-columns:
    var(--layout-sidebar-width, var(--sidebar-width))
    1fr
    var(--layout-properties-width, var(--properties-width));
  grid-template-areas:
    "toolbar toolbar toolbar"
    "sidebar canvas properties";
  height: 100%;
  width: 100%;
}

.toolbar {
  grid-area: toolbar;
  position: relative;
  z-index: 10;
}

.sidebar {
  grid-area: sidebar;
  min-height: 0;
  overflow-y: auto;
}

.canvas {
  grid-area: canvas;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  box-shadow: inset 1px 0 3px rgba(0, 0, 0, 0.04), inset -1px 0 3px rgba(0, 0, 0, 0.04);
}

.properties {
  grid-area: properties;
  min-height: 0;
